import anthropic
from dataclasses import dataclass, field

client = anthropic.Anthropic()

@dataclass
class TicketRouter:
    categories: list[str]
    _examples: list[tuple[str, str]] = field(default_factory=list)

    def add_example(self, ticket: str, category: str) -> "TicketRouter":
        assert category in self.categories, f"Unknown category: {category}"
        self._examples.append((ticket, category))
        return self

    def _format_example(self, ticket: str, category: str = "") -> str:
        lines = [f"Ticket: {ticket}", "Category:"]
        if category:
            lines[-1] += f" {category}"
        return "\n".join(lines)

    def build_prompt(self, ticket: str) -> str:
        parts = [self._format_example(t, c) for t, c in self._examples]
        parts.append(self._format_example(ticket))
        return "\n\n".join(parts)

    def classify(self, ticket: str) -> str:
        prompt = self.build_prompt(ticket)
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=20,
            temperature=0.0,
            stop_sequences=["\n"],
            messages=[{"role": "user", "content": prompt}],
        )
        result = resp.content[0].text.strip()
        if result not in self.categories:
            raise ValueError(f"Unexpected category '{result}' for ticket: {ticket}")
        return result


router = TicketRouter(categories=["billing", "technical", "returns", "general"])
router.add_example("I was charged twice for my order last week.", "billing")
router.add_example("The app crashes when I tap the settings icon.", "technical")
router.add_example("I want to send back the jacket I bought, it does not fit.", "returns")
router.add_example("When does your store open on Sundays?", "general")

test_tickets = [
    "My credit card was declined even though I have funds.",
    "The download speed is extremely slow on my device.",
    "I received the wrong colour, can I exchange it?",
    "Do you offer student discounts?",
]

for ticket in test_tickets:
    try:
        category = router.classify(ticket)
        print(f"[{category:10s}] {ticket}")
    except ValueError as e:
        print(f"[PARSE_ERR  ] {e}")
